query:
{
  connectors(
    where: {
      cloudProvider: { eq: "entra" }
      conditionalAccessPolicies_NONE: {
        conditions: {
          NOT: {
            excludeUsers: { eq: [] }
            OR: [
              { includeUsers: { eq: [] } }
              { includeGroups: { eq: [] } }
              { includeRoles: { eq: [] } }
            ]
          }
          includeApplications_INCLUDES: "All"
          clientAppTypes_INCLUDES: "all"
        }
        grantControls: { builtInControls_INCLUDES: "mfa" }
      }
    }
  ) {
    ...AssetFragment
  }
}
